import numpy as np

def S_gate():
    """Return the S gate matrix."""
    return np.array([[1, 0], [0, 1j]], dtype=complex)

def T_gate():
    """Return the T gate matrix."""
    return np.array([[1, 0], [0, np.exp(1j * np.pi/4)]], dtype=complex)

def P_gate(theta):
    """Return the general phase gate P(θ)."""
    return np.array([[1, 0], [0, np.exp(1j * theta)]], dtype=complex)

def verify_hierarchy():
    """Verify the gate hierarchy."""
    S = S_gate()
    T = T_gate()
    Z = np.array([[1, 0], [0, -1]], dtype=complex)
    I = np.eye(2, dtype=complex)

    return {
        'T² = S': np.allclose(T @ T, S),
        'S² = Z': np.allclose(S @ S, Z),
        'T⁴ = Z': np.allclose(np.linalg.matrix_power(T, 4), Z),
        'T⁸ = I': np.allclose(np.linalg.matrix_power(T, 8), I),
        'P(π/2) = S': np.allclose(P_gate(np.pi/2), S),
        'P(π/4) = T': np.allclose(P_gate(np.pi/4), T),
        'P(π) = Z': np.allclose(P_gate(np.pi), Z),
    }

# Test
S = S_gate()
T = T_gate()
print("S gate:\n", S)
print("\nT gate:\n", np.round(T, 4))

results = verify_hierarchy()
for relation, verified in results.items():
    print(f"{'✓' if verified else '✗'} {relation}")
